const W=Math.min(innerWidth,480),H=innerHeight;class S extends Phaser.Scene{create(){this.add.rectangle(W/2,H/2,W,H,0x0b0b0b);this.p=this.add.circle(40,H-40,10,0x86efac);this.physics.add.existing(this.p);this.p.body.setCollideWorldBounds(true);this.goal=this.add.rectangle(W-30,30,20,20,0xfacc15);this.walls=this.physics.add.staticGroup();for(let i=0;i<7;i++){const r=this.add.rectangle(80+i*50,120+((i%3)*90),60,14,0x333);this.physics.add.existing(r,true);this.walls.add(r);}this.guards=this.physics.add.group();for(let i=0;i<3;i++){const g=this.add.circle(120+i*110,220,10,0xf87171);this.physics.add.existing(g);g.dir=i%2?1:-1;this.guards.add(g);}this.physics.add.collider(this.p,this.walls);this.physics.add.overlap(this.p,this.goal,()=>this.win());this.physics.add.overlap(this.p,this.guards,()=>this.fail());this.light=this.add.circle(this.p.x,this.p.y,90,0x000000,0.55).setBlendMode('MULTIPLY');this.c=this.input.keyboard.createCursorKeys();this.r=this.input.keyboard.addKey('R');}win(){if(this.endd)return;this.endd=true;this.add.text(W/2,H/2,'CLEAR!\nR',{align:'center'}).setOrigin(.5);}fail(){if(this.endd)return;this.endd=true;this.add.text(W/2,H/2,'DETECTED\nR',{align:'center'}).setOrigin(.5);}update(){if(this.r.isDown)this.scene.restart();if(this.endd)return;const b=this.p.body;b.setVelocity(0);if(this.c.left.isDown)b.setVelocityX(-150);else if(this.c.right.isDown)b.setVelocityX(150);if(this.c.up.isDown)b.setVelocityY(-150);else if(this.c.down.isDown)b.setVelocityY(150);this.guards.getChildren().forEach(g=>{g.x+=g.dir*1.4;if(g.x<40||g.x>W-40)g.dir*=-1;});this.light.setPosition(this.p.x,this.p.y);}}new Phaser.Game({type:Phaser.AUTO,parent:'game',width:W,height:H,physics:{default:'arcade'},scene:[S]});